#include <bits/stdc++.h>
using namespace std;

int main(){
    int k,a1=0,a5=0,a10=0;
    cin>>k;
    for(int i=0;i<k;i++){
        int d;
        cin>>d;
        if (d==1){
            a1=a1+1;
        }
        else if (d==5){
            a5=a5+1;
        }
        else if (d==10){
            a10=a10+1;
        }
    }
    cout<<a1<<endl;
    cout<<a5<<endl;
    cout<<a10<<endl;
    return 0;
}
